package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * A class for generating a concise set of test cases.
 */
public class ConciseSetGenerator {

    /**
     * Finds a minimal set of test cases that covers all buggy implementations.
     * Uses a greedy set cover algorithm.
     *
     * @param results the test results
     * @return a set of test cases that covers all buggy implementations
     */
    public static Set<TestCase> setCover(TestResults results) {
        // We'll be working with a copy of the wrong set to avoid mutation
        Set<Integer> uncoveredFiles = new HashSet<>(results.getWrongSet());
        List<TestCase> allCases = new ArrayList<>();
        List<Set<Integer>> caseToFiles = new ArrayList<>();

        // Also copy the case-to-files mapping
        for (Set<Integer> filesCaught : results.getCaseToFiles()) {
            caseToFiles.add(new HashSet<>(filesCaught));
        }

        Set<TestCase> selectedTestCases = new HashSet<>();

        // While there are still uncovered failing implementations
        while (!uncoveredFiles.isEmpty()) {
            int maxUncoveredCaught = -1;
            int bestCaseIndex = -1;

            // Iterate through all test cases to find the one that catches the most
            // currently uncovered files
            for (int i = 0; i < caseToFiles.size(); i++) {
                Set<Integer> filesCaughtByThisCase = caseToFiles.get(i);

                // Count how many of the files caught by this case are currently uncovered
                int count = 0;
                for (Integer fileIdx : filesCaughtByThisCase) {
                    if (uncoveredFiles.contains(fileIdx)) {
                        count++;
                    }
                }

                // If this case is better than the current best, update it.
                // We use > to pick the first one in case of a tie, for determinism.
                if (count > maxUncoveredCaught) {
                    maxUncoveredCaught = count;
                    bestCaseIndex = i;
                }
            }

            // If we didn't find any test case that catches more uncovered files, break
            // (this shouldn't happen if wrongSet is consistent with caseToFiles)
            if (bestCaseIndex == -1 || maxUncoveredCaught == 0) {
                break;
            }

            // Add the best test case to our selected set
            TestCase bestCase = results.getTestCase(bestCaseIndex);
            selectedTestCases.add(bestCase);

            // Mark all files caught by this test case as covered
            uncoveredFiles.removeAll(caseToFiles.get(bestCaseIndex));
        }

        return selectedTestCases;
    }
}

